args.sparql:
SELECT ?winner ?winnerLabel ?year WHERE {
  ?award wdt:P1126 wd:Q858082 ; 
         wdt:P31 wd:Q119870.
  ?award p:P1346 ?statement .
  ?statement pq:P585 ?year .
  ?statement ps:P1346 ?winner .
  ?winner rdfs:label ?winnerLabel .
  FILTER(LANGMATCHES(LANG(?winnerLabel), 'en'))
} ORDER BY DESC(?year) LIMIT 1

